/* ---------- edger8r signature adapters ----------------------------------- */

static inline sgx_status_t ecall_noop_wr(sgx_enclave_id_t eid) {
    sgx_status_t retval = SGX_SUCCESS;
    return ecall_noop(eid, &retval);
}

static inline sgx_status_t ecall_phase2_keygen_batch_wr(
    sgx_enclave_id_t eid, uint32_t batch_size, double *inner_ms) {
    sgx_status_t retval = SGX_SUCCESS;
    return ecall_phase2_keygen_batch(eid, &retval, batch_size, inner_ms);
}

static inline sgx_status_t ecall_phase4_signcrypt_single_wr(
    sgx_enclave_id_t eid, const uint8_t *pk_r_kem, uint32_t file_size_bytes, double *inner_ms) {
    sgx_status_t retval = SGX_SUCCESS;
    return ecall_phase4_signcrypt_single(eid, &retval, pk_r_kem, file_size_bytes, inner_ms);
}

static inline sgx_status_t ecall_phase4_signcrypt_batch_wr(
    sgx_enclave_id_t eid, uint32_t n_requests, const uint8_t *pk_r_kem, double *inner_ms) {
    sgx_status_t retval = SGX_SUCCESS;
    return ecall_phase4_signcrypt_batch(eid, &retval, n_requests, pk_r_kem, inner_ms);
}

static inline sgx_status_t ecall_phase6_rebind_single_wr(
    sgx_enclave_id_t eid, double *inner_ms) {
    sgx_status_t retval = SGX_SUCCESS;
    return ecall_phase6_rebind_single(eid, &retval, inner_ms);
}

static inline sgx_status_t ecall_phase6_lazy_revoke_wr(
    sgx_enclave_id_t eid, uint32_t n_revoked, double *inner_ms) {
    sgx_status_t retval = SGX_SUCCESS;
    return ecall_phase6_lazy_revoke(eid, &retval, n_revoked, inner_ms);
}

/* ---------- timing helpers ------------------------------------------------ */

using Clock = std::chrono::high_resolution_clock;

static double now_ms() {
    return std::chrono::duration<double, std::milli>(
        Clock::now().time_since_epoch()).count();
}

/* Measure total ECALL time (entry + ops + exit) */
#define TIME_ECALL(call, ms_var) \
    do { \
        auto _t0 = Clock::now(); \
        call; \
        (ms_var) = std::chrono::duration<double, std::milli>( \
            Clock::now() - _t0).count(); \
    } while (0)

/* ---------- statistics helpers -------------------------------------------- */

static double vec_mean(const std::vector<double> &v) {
    if (v.empty()) return 0.0;
    return std::accumulate(v.begin(), v.end(), 0.0) / v.size();
}
static double vec_std(const std::vector<double> &v) {
    if (v.size() < 2) return 0.0;
    double m = vec_mean(v);
    double s = 0.0;
    for (double x : v) s += (x - m) * (x - m);
    return sqrt(s / v.size());
}

/* ---------- CSV / JSON output --------------------------------------------- */

struct ResultTable {
    std::vector<std::string> columns;
    std::vector<std::vector<double>> data;    /* data[col][row] */

    void add_column(const std::string &name) {
        columns.push_back(name);
        data.emplace_back();
    }
    std::vector<double> &col(const std::string &name) {
        for (size_t i = 0; i < columns.size(); i++)
            if (columns[i] == name) return data[i];
        throw std::runtime_error("column not found: " + name);
    }
    void push(const std::string &col_name, double val) {
        col(col_name).push_back(val);
    }
    size_t nrows() const { return data.empty() ? 0 : data[0].size(); }

    void save(const std::string &base_path) const {
        /* CSV */
        std::ofstream csv(base_path + ".csv");
        for (size_t c = 0; c < columns.size(); c++)
            csv << (c ? "," : "") << columns[c];
        csv << "\n";
        for (size_t r = 0; r < nrows(); r++) {
            for (size_t c = 0; c < columns.size(); c++)
                csv << (c ? "," : "") << data[c][r];
            csv << "\n";
        }

        /* JSON */
        std::ofstream js(base_path + ".json");
        js << "{\n";
        for (size_t c = 0; c < columns.size(); c++) {
            js << "  \"" << columns[c] << "\": [";
            for (size_t r = 0; r < data[c].size(); r++)
                js << (r ? ", " : "") << data[c][r];
            js << "]" << (c + 1 < columns.size() ? "," : "") << "\n";
        }
        js << "}\n";
        printf("Saved: %s.csv\n", base_path.c_str());
    }
};

/* ---------- calibrate ECALL overhead -------------------------------------- */

double calibrate_ecall_overhead_ms(sgx_enclave_id_t eid, int n_samples) {
    double sum = 0.0;
    for (int i = 0; i < n_samples; i++) {
        double ms;
        TIME_ECALL(ecall_noop_wr(eid), ms);
        sum += ms;
    }
    return sum / n_samples;
}

/* Calibrate per-request inner ops cost for Phase 4 signcrypt.
 * Runs one ECALL for a batch of `batch_size` and divides by batch_size. */
static double calibrate_per_req_signcrypt_ms(sgx_enclave_id_t eid, int batch_size) {
    uint8_t pk_kem[1184];
    RAND_bytes(pk_kem, 1184);

    double sum = 0.0;
    int n = 3;
    for (int i = 0; i < n; i++) {
        double total_ms, inner_ms;
        TIME_ECALL(ecall_phase4_signcrypt_batch_wr(eid, batch_size, pk_kem, &inner_ms),
                   total_ms);
        sum += total_ms;
    }
    return (sum / n) / batch_size;
}

/* ============================================================================
 * Experiment 1: Phase 4 Signcrypt vs File Size
 * ============================================================================
 *
 * X-axis: file size (1KB → 100MB)
 * Y-axis: computation cost (ms)
 * PQSCAAS Phase 4 is file-size INDEPENDENT (operates on 32-byte key material).
 * Baselines include AEAD scaled to file size for fair comparison.
 */
void exp1_phase4_vs_filesize(sgx_enclave_id_t eid) {
    printf("======================================================================\n");
    printf("Experiment 1: Phase 4 Signcrypt vs File Size\n");
    printf("======================================================================\n");

    const int NUM_TRIALS = 50;
    const size_t SIZES[] = {1024, 10240, 102400, 1048576, 10485760, 104857600};
    const char  *LABELS[] = {"1 KB","10 KB","100 KB","1 MB","10 MB","100 MB"};
    const int    N_SIZES  = 6;

    uint8_t pk_kem[1184];
    RAND_bytes(pk_kem, 1184);

    ResultTable rt;
    for (auto &c : {"file_size_bytes","PQSCAAS_mean","PQSCAAS_std",
                    "Sinha2026_mean","Sinha2026_std",
                    "Yu2021_mean","Yu2021_std",
                    "Bai2025_mean","Bai2025_std"})
        rt.add_column(c);
    /* labels stored in a separate vector (strings, not doubles) */
    std::vector<std::string> size_labels;

    for (int si = 0; si < N_SIZES; si++) {
        size_t size = SIZES[si];
        size_t actual = size > 10485760 ? 10485760 : size;
        double scale  = (double)size / (double)actual;

        printf("[Exp 1] File size = %s ...\n", LABELS[si]);

        std::vector<double> pq_r, sinha_r, yu_r, bai_r;

        for (int trial = 0; trial < NUM_TRIALS; trial++) {
            /* PQSCAAS Phase 4: file-size independent (measures real ECALL) */
            double total_ms, inner_ms;
            TIME_ECALL(
                ecall_phase4_signcrypt_single_wr(eid, pk_kem, (uint32_t)actual, &inner_ms),
                total_ms
            );
            pq_r.push_back(total_ms);

            /* Baselines: PQ ops + AEAD scaled to requested size */
            double s = sinha_client_signcrypt(actual);
            double y = yu_client_signcrypt(actual);
            double b = bai_client_signcrypt(actual);

            sinha_r.push_back(scale > 1.0 ? s * scale : s);
            yu_r.push_back(   scale > 1.0 ? y * scale : y);
            bai_r.push_back(  scale > 1.0 ? b * scale : b);
        }

        size_labels.push_back(LABELS[si]);
        rt.push("file_size_bytes", (double)size);
        rt.push("PQSCAAS_mean",    vec_mean(pq_r));
        rt.push("PQSCAAS_std",     vec_std(pq_r));
        rt.push("Sinha2026_mean",  vec_mean(sinha_r));
        rt.push("Sinha2026_std",   vec_std(sinha_r));
        rt.push("Yu2021_mean",     vec_mean(yu_r));
        rt.push("Yu2021_std",      vec_std(yu_r));
        rt.push("Bai2025_mean",    vec_mean(bai_r));
        rt.push("Bai2025_std",     vec_std(bai_r));

        printf("  PQSCAAS: %.3f ± %.3f ms\n", vec_mean(pq_r), vec_std(pq_r));
        printf("  Sinha: %.3f | Yu: %.3f | Bai: %.3f ms\n",
               vec_mean(sinha_r), vec_mean(yu_r), vec_mean(bai_r));
    }
    rt.save("results/exp1_phase4_vs_filesize");
}

/* ============================================================================
 * Experiment 2: Signcrypt Batch vs Number of Requests
 * ============================================================================ */
void exp2_signcrypt_batch_vs_requests(sgx_enclave_id_t eid) {
    printf("======================================================================\n");
    printf("Experiment 2: Signcrypt with Batching vs # Requests (Sequential)\n");
    printf("======================================================================\n");

    const int    NUM_TRIALS      = 50;
    const int    BATCH_CAPACITY  = 50;
    const double GAP_FRACTION    = 0.05;
    const int    N_VALUES[]      = {10, 45, 120, 520, 1050, 5120, 10020};
    const int    N_N             = 7;

    uint8_t pk_kem[1184];
    RAND_bytes(pk_kem, 1184);

    double ecall_overhead = calibrate_ecall_overhead_ms(eid, 20);
    double per_req = calibrate_per_req_signcrypt_ms(eid, BATCH_CAPACITY);

    ResultTable rt;
    for (auto &c : {"n_requests",
                    "PQSCAAS_no_timeout_mean","PQSCAAS_no_timeout_std",
                    "PQSCAAS_with_timeout_mean","PQSCAAS_with_timeout_std",
                    "Sinha2026_mean","Sinha2026_std",
                    "Yu2021_mean","Yu2021_std",
                    "Bai2025_mean","Bai2025_std"})
        rt.add_column(c);

    /* Calibrate full batch cost once */
    double per_full_batch;
    {
        double sum = 0;
        for (int i = 0; i < 3; i++) {
            double total_ms, inner_ms;
            TIME_ECALL(
                ecall_phase4_signcrypt_batch_wr(eid, BATCH_CAPACITY, pk_kem, &inner_ms),
                total_ms
            );
            sum += total_ms;
        }
        per_full_batch = sum / 3.0;
    }

    auto cost_partial = [&](int n_partial) -> double {
        return ecall_overhead + n_partial * per_req;
    };

    for (int ni = 0; ni < N_N; ni++) {
        int N = N_VALUES[ni];
        int trials = (N <= 1000) ? NUM_TRIALS : std::max(10, NUM_TRIALS / 5);
        printf("[Exp 2] N = %d requests ...\n", N);

        std::vector<double> nt_r, wt_r, sinha_r, yu_r, bai_r;

        for (int trial = 0; trial < trials; trial++) {
            int n_full    = N / BATCH_CAPACITY;
            int n_partial = N % BATCH_CAPACITY;

            /* PQSCAAS no-timeout (analytical) */
            double t_nt = n_full * per_full_batch;
            if (n_partial > 0) {
                double t_p = cost_partial(n_partial);
                double stall = (double)(BATCH_CAPACITY - n_partial) / BATCH_CAPACITY;
                t_nt += t_p + t_p * stall * GAP_FRACTION * 10.0;
            }
            nt_r.push_back(t_nt);

            /* PQSCAAS with-timeout (analytical) */
            double t_wt = n_full * per_full_batch;
            if (n_partial > 0) t_wt += cost_partial(n_partial);
            wt_r.push_back(t_wt);

            /* Baselines: per-request * N */
            sinha_r.push_back(sinha_client_signcrypt(1024) * N);
            yu_r.push_back(   yu_client_signcrypt(1024)    * N);
            bai_r.push_back(  bai_client_signcrypt(1024)   * N);
        }

        rt.push("n_requests",                 (double)N);
        rt.push("PQSCAAS_no_timeout_mean",     vec_mean(nt_r));
        rt.push("PQSCAAS_no_timeout_std",      vec_std(nt_r));
        rt.push("PQSCAAS_with_timeout_mean",   vec_mean(wt_r));
        rt.push("PQSCAAS_with_timeout_std",    vec_std(wt_r));
        rt.push("Sinha2026_mean",              vec_mean(sinha_r));
        rt.push("Sinha2026_std",               vec_std(sinha_r));
        rt.push("Yu2021_mean",                 vec_mean(yu_r));
        rt.push("Yu2021_std",                  vec_std(yu_r));
        rt.push("Bai2025_mean",                vec_mean(bai_r));
        rt.push("Bai2025_std",                 vec_std(bai_r));

        printf("  PQ no-timeout: %.2f ms | with-timeout: %.2f ms\n",
               vec_mean(nt_r), vec_mean(wt_r));
        printf("  Bai: %.2f | Sinha: %.2f | Yu: %.2f ms\n",
               vec_mean(bai_r), vec_mean(sinha_r), vec_mean(yu_r));
    }
    rt.save("results/exp2_signcrypt_batch_vs_requests");
}

/* ============================================================================
 * Experiment 3: Phase 5 Unsigncrypt vs File Size
 * ============================================================================
 *
 * Phase 5 is on the UNTRUSTED recipient side: DSA verify (mock) + KEM decap
 * (mock) + HKDF + AEAD decrypt (real). No enclave entry.
 */

static double phase5_decrypt_untrusted(size_t ct_size) {
    /* Mirrors scheme.py::phase5_decrypt */
    double total = 0.0;

    /* ML-DSA verify (mock) */
    total += untrusted_sample_lognormal(0.125, 0.006);

    /* ML-KEM decap (mock) */
    total += untrusted_sample_lognormal(0.065, 0.004);

    /* HKDF K_mask */
    auto [_, hkdf_ms] = hkdf_sha256(
        (const uint8_t*)"kshared", 7, nullptr, 0,
        (const uint8_t*)"hct", 3, 32);
    total += hkdf_ms;

    /* XOR K_d = W XOR K_mask — negligible, skip */

    /* AEAD decrypt */
    uint8_t key[32];
    RAND_bytes(key, 32);
    std::vector<uint8_t> pt(ct_size, 0xAB);
    auto [ct, _ems] = aead_encrypt_256(key, pt.data(), ct_size,
                                       (const uint8_t*)"aad", 3);
    auto [_pt, dec_ms] = aead_decrypt_256(key, ct.data(), ct.size(),
                                          (const uint8_t*)"aad", 3);
    total += dec_ms;

    return total;
}

void exp3_phase5_vs_filesize(sgx_enclave_id_t eid) {
    (void)eid;
    printf("======================================================================\n");
    printf("Experiment 3: Phase 5 Unsigncrypt vs File Size\n");
    printf("======================================================================\n");

    const int NUM_TRIALS = 50;
    const size_t SIZES[] = {1024, 10240, 102400, 1048576, 10485760, 104857600};
    const char  *LABELS[] = {"1 KB","10 KB","100 KB","1 MB","10 MB","100 MB"};

    ResultTable rt;
    for (auto &c : {"file_size_bytes","PQSCAAS_mean","PQSCAAS_std",
                    "Sinha2026_mean","Sinha2026_std",
                    "Yu2021_mean","Yu2021_std","Bai2025_mean","Bai2025_std"})
        rt.add_column(c);

    for (int si = 0; si < 6; si++) {
        size_t size   = SIZES[si];
        size_t actual = size > 10485760 ? 10485760 : size;
        double scale  = (double)size / (double)actual;

        printf("[Exp 3] File size = %s ...\n", LABELS[si]);
        std::vector<double> pq_r, sinha_r, yu_r, bai_r;

        for (int trial = 0; trial < NUM_TRIALS; trial++) {
            double t_pq = phase5_decrypt_untrusted(actual) * (scale > 1.0 ? scale : 1.0);
            pq_r.push_back(t_pq);

            double s = sinha_decrypt(actual) * (scale > 1.0 ? scale : 1.0);
            double y = yu_decrypt(actual)    * (scale > 1.0 ? scale : 1.0);
            double b = bai_decrypt(actual)   * (scale > 1.0 ? scale : 1.0);
            sinha_r.push_back(s);
            yu_r.push_back(y);
            bai_r.push_back(b);
        }

        rt.push("file_size_bytes", (double)size);
        rt.push("PQSCAAS_mean",   vec_mean(pq_r));   rt.push("PQSCAAS_std",  vec_std(pq_r));
        rt.push("Sinha2026_mean", vec_mean(sinha_r)); rt.push("Sinha2026_std",vec_std(sinha_r));
        rt.push("Yu2021_mean",    vec_mean(yu_r));    rt.push("Yu2021_std",   vec_std(yu_r));
        rt.push("Bai2025_mean",   vec_mean(bai_r));   rt.push("Bai2025_std",  vec_std(bai_r));

        printf("  PQSCAAS: %.3f ms | Bai: %.3f ms\n", vec_mean(pq_r), vec_mean(bai_r));
        printf("  Sinha:   %.3f ms | Yu:  %.3f ms\n", vec_mean(sinha_r), vec_mean(yu_r));
    }
    rt.save("results/exp3_phase5_vs_filesize");
}

