/* ============================================================================
 * Experiment 5: Signcrypt Throughput vs Concurrent Workload
 * ============================================================================ */
void exp5_signcrypt_throughput(sgx_enclave_id_t eid) {
    printf("======================================================================\n");
    printf("Experiment 5: Signcrypt Throughput vs Concurrent Workload\n");
    printf("======================================================================\n");

    const int    NUM_TRIALS     = 50;
    const int    BATCH_CAPACITY = 50;
    const double GAP_FRACTION   = 0.05;
    const int    WORKLOADS[]    = {1,2,4,8,16,32,64,128,256,512,1024};
    const int    N_W            = 11;

    uint8_t pk_kem[1184];
    RAND_bytes(pk_kem, 1184);

    double ecall_overhead = calibrate_ecall_overhead_ms(eid, 20);
    double per_req        = calibrate_per_req_signcrypt_ms(eid, BATCH_CAPACITY);

    double per_full_batch;
    {
        double sum = 0;
        for (int i = 0; i < 3; i++) {
            double total_ms, inner_ms;
            TIME_ECALL(
                ecall_phase4_signcrypt_batch_wr(eid, BATCH_CAPACITY, pk_kem, &inner_ms),
                total_ms
            );
            sum += total_ms;
        }
        per_full_batch = sum / 3.0;
    }

    auto cost_partial = [&](int n) { return ecall_overhead + n * per_req; };
    auto throughput   = [](double total_ms, int n_req) -> double {
        return total_ms > 0.0 ? n_req / (total_ms / 1000.0) : 0.0;
    };

    ResultTable rt;
    for (auto &c : {"workload",
                    "PQSCAAS_no_timeout_mean","PQSCAAS_no_timeout_std",
                    "PQSCAAS_with_timeout_mean","PQSCAAS_with_timeout_std",
                    "Sinha2026_mean","Sinha2026_std",
                    "Yu2021_mean","Yu2021_std","Bai2025_mean","Bai2025_std"})
        rt.add_column(c);

    for (int wi = 0; wi < N_W; wi++) {
        int W = WORKLOADS[wi];
        int trials = (W <= 128) ? NUM_TRIALS : std::max(10, NUM_TRIALS / 5);
        printf("[Exp 5] Workload = %d ...\n", W);

        std::vector<double> nt_tp, wt_tp, sinha_tp, yu_tp, bai_tp;

        for (int trial = 0; trial < trials; trial++) {
            int n_full    = W / BATCH_CAPACITY;
            int n_partial = W % BATCH_CAPACITY;

            double t_nt = n_full * per_full_batch;
            if (n_partial > 0) {
                double t_p = cost_partial(n_partial);
                double stall = (double)(BATCH_CAPACITY - n_partial) / BATCH_CAPACITY;
                t_nt += t_p + t_p * stall * GAP_FRACTION * 10.0;
            }
            nt_tp.push_back(throughput(t_nt, W));

            double t_wt = n_full * per_full_batch;
            if (n_partial > 0) t_wt += cost_partial(n_partial);
            wt_tp.push_back(throughput(t_wt, W));

            double s = sinha_client_signcrypt(1024);
            double y = yu_client_signcrypt(1024);
            double b = bai_client_signcrypt(1024);
            sinha_tp.push_back(throughput(s * W, W));
            yu_tp.push_back(   throughput(y * W, W));
            bai_tp.push_back(  throughput(b * W, W));
        }

        rt.push("workload",                   (double)W);
        rt.push("PQSCAAS_no_timeout_mean",    vec_mean(nt_tp));  rt.push("PQSCAAS_no_timeout_std",  vec_std(nt_tp));
        rt.push("PQSCAAS_with_timeout_mean",  vec_mean(wt_tp));  rt.push("PQSCAAS_with_timeout_std",vec_std(wt_tp));
        rt.push("Sinha2026_mean",             vec_mean(sinha_tp));rt.push("Sinha2026_std",          vec_std(sinha_tp));
        rt.push("Yu2021_mean",                vec_mean(yu_tp));   rt.push("Yu2021_std",             vec_std(yu_tp));
        rt.push("Bai2025_mean",               vec_mean(bai_tp));  rt.push("Bai2025_std",            vec_std(bai_tp));

        printf("  PQ no-to: %.0f req/s | with-to: %.0f req/s\n",
               vec_mean(nt_tp), vec_mean(wt_tp));
        printf("  Bai: %.0f | Sinha: %.0f | Yu: %.0f req/s\n",
               vec_mean(bai_tp), vec_mean(sinha_tp), vec_mean(yu_tp));
    }
    rt.save("results/exp5_signcrypt_throughput");
}

/* ============================================================================
 * Experiment 6: Unsigncrypt Throughput vs Concurrent Workload
 * ============================================================================ */
void exp6_unsigncrypt_throughput(sgx_enclave_id_t eid) {
    (void)eid;
    printf("======================================================================\n");
    printf("Experiment 6: Unsigncrypt Throughput vs Concurrent Workload\n");
    printf("======================================================================\n");

    const int NUM_TRIALS  = 50;
    const int WORKLOADS[] = {1,2,4,8,16,32,64,128,256,512,1024};
    const int N_W         = 11;

    auto throughput = [](double total_ms, int n) {
        return total_ms > 0.0 ? n / (total_ms / 1000.0) : 0.0;
    };

    ResultTable rt;
    for (auto &c : {"workload","PQSCAAS_mean","PQSCAAS_std",
                    "Sinha2026_mean","Sinha2026_std",
                    "Yu2021_mean","Yu2021_std","Bai2025_mean","Bai2025_std"})
        rt.add_column(c);

    for (int wi = 0; wi < N_W; wi++) {
        int W = WORKLOADS[wi];
        int trials = (W <= 128) ? NUM_TRIALS : std::max(10, NUM_TRIALS / 5);
        printf("[Exp 6] Workload = %d ...\n", W);

        std::vector<double> pq_tp, sinha_tp, yu_tp, bai_tp;
        for (int trial = 0; trial < trials; trial++) {
            double pq_s    = phase5_decrypt_untrusted(1024);
            double sinha_s = sinha_decrypt(1024);
            double yu_s    = yu_decrypt(1024);
            double bai_s   = bai_decrypt(1024);

            pq_tp.push_back(   throughput(pq_s * W, W));
            sinha_tp.push_back(throughput(sinha_s * W, W));
            yu_tp.push_back(   throughput(yu_s * W, W));
            bai_tp.push_back(  throughput(bai_s * W, W));
        }

        rt.push("workload",       (double)W);
        rt.push("PQSCAAS_mean",   vec_mean(pq_tp));    rt.push("PQSCAAS_std",  vec_std(pq_tp));
        rt.push("Sinha2026_mean", vec_mean(sinha_tp)); rt.push("Sinha2026_std",vec_std(sinha_tp));
        rt.push("Yu2021_mean",    vec_mean(yu_tp));    rt.push("Yu2021_std",   vec_std(yu_tp));
        rt.push("Bai2025_mean",   vec_mean(bai_tp));   rt.push("Bai2025_std",  vec_std(bai_tp));

        printf("  PQSCAAS: %.0f req/s | Bai: %.0f req/s\n",
               vec_mean(pq_tp), vec_mean(bai_tp));
        printf("  Sinha:   %.0f req/s | Yu:  %.0f req/s\n",
               vec_mean(sinha_tp), vec_mean(yu_tp));
    }
    rt.save("results/exp6_unsigncrypt_throughput");
}

/* ============================================================================
 * Experiment 7: Key Revocation — Lazy vs Non-Lazy
 * ============================================================================
 *
 * Mirrors scheme.py::phase6_lazy_revocation / phase6_nonlazy_revocation.
 * Multi-enclave parallelism: analytical formula with real seal/unseal calibration.
 */
void exp7_revocation(sgx_enclave_id_t eid) {
    printf("======================================================================\n");
    printf("Experiment 7: Key Revocation — Lazy vs Non-Lazy\n");
    printf("Active users = 500,000\n");
    printf("======================================================================\n");

    const int    NUM_TRIALS    = 30;
    const int    ACTIVE_USERS  = 500000;
    const int    BATCH_SIZE    = 64;
    const int    NUM_ENCLAVES  = 8;
    const int    REVOKED[]     = {1, 10, 100, 1000, 10000, 100000};
    const int    N_R           = 6;

    /* Calibrate per-user rebind cost from a real enclave call */
    double rebind_ms;
    ecall_phase6_rebind_single_wr(eid, &rebind_ms);

    /* Calibrate enclave enter/exit overhead */
    double enter_exit = calibrate_ecall_overhead_ms(eid, 20);

    ResultTable rt;
    for (auto &c : {"n_revoked","Lazy_mean","Lazy_std","NonLazy_mean","NonLazy_std"})
        rt.add_column(c);

    for (int ri = 0; ri < N_R; ri++) {
        int n_rev = REVOKED[ri];
        int trials = (n_rev >= 10000) ? std::max(5, NUM_TRIALS / 5) : NUM_TRIALS;
        printf("[Exp 7] Revoked users = %d ...\n", n_rev);

        std::vector<double> lazy_r, nonlazy_r;

        for (int trial = 0; trial < trials; trial++) {
            /* ---- Lazy revocation (real ECALL to the enclave) ---- */
            double lazy_ms;
            double total_ecall_ms;
            TIME_ECALL(
                ecall_phase6_lazy_revoke_wr(eid, (uint32_t)n_rev, &lazy_ms),
                total_ecall_ms
            );
            lazy_r.push_back(total_ecall_ms);

            /* ---- Non-lazy revocation (analytical formula) ---- */
            /* Revocation list update (same as lazy) */
            double revoke_list_cost = total_ecall_ms;

            /* Distribute active users across 8 enclaves */
            int users_per_enclave = (ACTIVE_USERS + NUM_ENCLAVES - 1) / NUM_ENCLAVES;
            int n_batches         = (users_per_enclave + BATCH_SIZE - 1) / BATCH_SIZE;

            /* Critical-path enclave cost */
            double rebind_cost =
                n_batches * enter_exit +
                users_per_enclave * rebind_ms;

            nonlazy_r.push_back(revoke_list_cost + rebind_cost);
        }

        rt.push("n_revoked",    (double)n_rev);
        rt.push("Lazy_mean",    vec_mean(lazy_r));     rt.push("Lazy_std",    vec_std(lazy_r));
        rt.push("NonLazy_mean", vec_mean(nonlazy_r));  rt.push("NonLazy_std", vec_std(nonlazy_r));

        printf("  Lazy:     %.3f ms\n",  vec_mean(lazy_r));
        printf("  Non-lazy: %.2f ms\n",  vec_mean(nonlazy_r));
    }
    rt.save("results/exp7_revocation");
}

/* ============================================================================
 * Experiment 8: Phase 2 Keygen vs Concurrent Users
 * ============================================================================
 *
 * PQSCAAS: batched multi-enclave (critical path = max share).
 * Baselines: sequential per-user cost × N.
 * Mirrors scheme.py::phase2_total_keygen_cost.
 */
void exp8_keygen_vs_users(sgx_enclave_id_t eid) {
    printf("======================================================================\n");
    printf("Experiment 8: Phase 2 Keygen vs Concurrent Users\n");
    printf("======================================================================\n");

    const int NUM_TRIALS   = 20;
    const int BATCH_SIZE   = 64;
    const int NUM_ENCLAVES = 8;
    const int N_VALUES[]   = {100, 1000, 10000, 100000, 500000};
    const int N_N          = 5;

    /* Calibrate per-user ops cost inside enclave:
     * run one batch of BATCH_SIZE, measure total ECALL, subtract enter/exit, divide */
    double enter_exit = calibrate_ecall_overhead_ms(eid, 20);
    double batch_total_ms;
    {
        double inner_ms;
        TIME_ECALL(ecall_phase2_keygen_batch_wr(eid, BATCH_SIZE, &inner_ms), batch_total_ms);
    }
    double per_user_ops = (batch_total_ms - enter_exit) / BATCH_SIZE;
    if (per_user_ops < 0) per_user_ops = batch_total_ms / BATCH_SIZE;

    ResultTable rt;
    for (auto &c : {"n_users","PQSCAAS_mean","PQSCAAS_std",
                    "Sinha2026_mean","Sinha2026_std",
                    "Yu2021_mean","Yu2021_std","Bai2025_mean","Bai2025_std"})
        rt.add_column(c);

    for (int ni = 0; ni < N_N; ni++) {
        int N = N_VALUES[ni];
        int trials = (N >= 100000) ? std::max(5, NUM_TRIALS / 4) : NUM_TRIALS;
        printf("[Exp 8] N = %d users ...\n", N);

        std::vector<double> pq_r, sinha_r, yu_r, bai_r;

        for (int trial = 0; trial < trials; trial++) {
            /* PQSCAAS: critical-path enclave (parallel across NUM_ENCLAVES) */
            int users_per_enclave = (N + NUM_ENCLAVES - 1) / NUM_ENCLAVES;
            int n_batches         = (users_per_enclave + BATCH_SIZE - 1) / BATCH_SIZE;

            double pq_t =
                n_batches * enter_exit +
                users_per_enclave * per_user_ops;
            pq_r.push_back(pq_t);

            /* Baselines: sample per-user cost × N (sequential) */
            int n_sample = std::min(20, N);
            double s_sum = 0, y_sum = 0, b_sum = 0;
            for (int j = 0; j < n_sample; j++) {
                s_sum += sinha_per_user_keygen();
                y_sum += yu_per_user_keygen();
                b_sum += bai_per_user_keygen();
            }
            sinha_r.push_back((s_sum / n_sample) * N);
            yu_r.push_back(   (y_sum / n_sample) * N);
            bai_r.push_back(  (b_sum / n_sample) * N);
        }

        rt.push("n_users",        (double)N);
        rt.push("PQSCAAS_mean",   vec_mean(pq_r));    rt.push("PQSCAAS_std",  vec_std(pq_r));
        rt.push("Sinha2026_mean", vec_mean(sinha_r)); rt.push("Sinha2026_std",vec_std(sinha_r));
        rt.push("Yu2021_mean",    vec_mean(yu_r));    rt.push("Yu2021_std",   vec_std(yu_r));
        rt.push("Bai2025_mean",   vec_mean(bai_r));   rt.push("Bai2025_std",  vec_std(bai_r));

        printf("  PQSCAAS: %.1f ms\n",     vec_mean(pq_r));
        printf("  Bai:     %.1f ms | Sinha: %.1f ms | Yu: %.1f ms\n",
               vec_mean(bai_r), vec_mean(sinha_r), vec_mean(yu_r));
    }
    rt.save("results/exp8_keygen_vs_users");
}
